+impl ArgpHeader {
+    fn is_empty(&self) -> bool {
+        self.options.is_null()
+            && self.parser.is_null()
+            && self.args_doc.is_null()
+            && self.doc.is_null()
+            && self.children.is_null()
+            && self.help_filter.is_null()
